@ARTICLE{10.1186/s12933-025-03059-y,
	author = {Thorson AS(1) and Schaefers KP(1) and Litts B(2)(3) and Rein J(1) and Adapa S(1) and Chinnarasu S(2)(4)(3) and Shapiro K(1) and Zhao Y(5) and Yu S(1)(4) and Recupido B(1) and Streng KJ(6) and Ahn IS(5) and Lan R(5) and Pierre-Louis O(6) and Forson D(1) and Bennett M(1) and Luviano H(6) and Saleem M(6) and Zhu L(2)(4)(3) and Yang X(5) and Kirabo A(6), M Stafford J(7)(8)(9)(10).},
	title = {Sex‐specific cardiovascular risk in estrogen‐treated androgen‐deprived males: metabolic characterization of glucose, adipose, and lipid pathways.},
	journal = {Cardiovasc Diabetol},
	year = {2026},
	abstract = {BACKGROUND: Estrogen therapy and androgen‐deprivation were once combined to treat prostate cancer (PrCa). Clinical studies later showed that prolonged estrogen exposure in androgen‐deprived men raises cardiovascular disease (CVD) risk, yet the metabolic pathways responsible remain unclear. METHODS: We generated an androgen‐deprived, 17β‐estradiol (E2)-treated mouse model by gonadectomizing male C57BL/6 J mice and implanting sub‐cutaneous delayed‐release E2 or vehicle pellets. Mice received a Western‐style diet and were housed at thermoneutrality to accelerate CVD‐risk phenotypes. Metabolic profiling included hyperinsulinemic‐euglycemic clamps, oral lipid and pyruvate tolerance tests, flow cytometry of immune cells, and single‐nucleus RNA sequencing of liver tissue. RESULTS: In hypogonadal males, E2 treatment induced several metabolic disturbances. During clamps, E2‐treated mice showed markedly elevated gluconeogenesis, corroborated by higher glucose peaks and AUC during pyruvate tolerance testing and by up‐regulation of hepatic Pck1 mRNA. Triglyceride (TG) clearance, which improves with E2 in females, was impaired in E2‐treated males: oral lipid‐tolerance testing revealed prolonged TG excursions, reduced maximal lipase activity, lower non‐lipase clearance at 6 h post-OLTT, and decreased free‐fatty‐acid peak levels. Hepatic lipase, VLDL clearance receptors Ldlr and Lrp1, and microsomal triglyceride transfer protein (MTP) transcripts were down‐regulated. SnRNA‐seq showed suppression of lipid‐clearance genes with E2 treatment in males. Subcutaneous adipocytes were hypertrophic, and flow cytometry identified increased TNFα‐positive macrophages, an inflammatory milieu that could promote insulin resistance. Cardiac morphology was modestly altered; E2‐treated males exhibited a larger left‐ventricular end‐diastolic diameter, while ejection fraction and arterial pressure remained unchanged. CONCLUSION: Estradiol administration in androgen‐deprived male mice produces a constellation of metabolic derangements-including enhanced hepatic gluconeogenesis, impaired TG clearance, and inflammatory adipocyte hypertrophy-that likely underlie the increased CVD risk observed clinically. The identified molecular nodes (PEPCK, hepatic lipase, LRP1, LDLR, MTP, and adipose‐macrophage TNFα) provide potential targets for mitigating estrogen‐induced CVD risk while preserving its therapeutic benefit for PrCa.},
	doi = {10.1186/s12933-025-03059-y},
	pmid = {41622197 [Indexed for MEDLINE]},
	note = {PMC12955195}
}

@ARTICLE{10.1038/s41598-026-35546-x,
	author = {Eslami Z(1) and Ghafi AG(2) and Wong A(3) and Asghari SH(4) and Asadi N(5) and Mirghani SJ(6).},
	title = {Additive effects of high intensity interval training and therapeutic adenosine on gene and protein expression in lipid metabolism and weight loss in high fat diet-induced obese rats.},
	journal = {Sci Rep},
	year = {2026},
	abstract = {There is significant interest in the development of comprehensive strategies to combat obesity. One such approach involves the combination of exercise training with pharmacological interventions. Recently, the injection of adenosine (Ade) has garnered attention as a potential adjunctive treatment. Forty-two male rats were assigned to two dietary groups for 25 weeks: normal diet and high-fat diet (HFD). After 13 weeks, the HFD group was randomly divided into 4 subgroups for a 12-week intervention: HFD + HIIT + Ade, HFD + HIIT, HFD + Ade and HFD control. The study comprised 4 phases:1) initiation and baseline weighing, 2) fattening, 3) first intervention (Ade 0.2 mg/kg + HIIT), and 4) second intervention (Ade 0.4 mg/kg + HIIT). The HFD + HIIT + Ade group exhibited a significant increase in the expression of AMPK, HSL and A2A receptor genes and proteins compared to other groups. The highest expression of the CGI-58 gene and protein was significantly observed in the HFD + HIIT group. The ACC gene expression was significantly higher in the HFD group, while the lowest expression was observed in the HFD + HIIT group. The most significant weight loss occurred in the HFD + HIIT + Ade group. HIIT activates lipolytic pathways while concurrently suppressing lipogenic pathways, effects that are enhanced by Ade administration. Moreover, HIIT alone can stimulate Ade-mediated lipolytic receptors, with these effects further augmented by optimal doses of Ade.},
	doi = {10.1038/s41598-026-35546-x},
	pmid = {41617762 [Indexed for MEDLINE]},
	note = {PMC12914024}
}

@ARTICLE{10.1111/jog.70185,
	author = {Asano F(1) and Momomura M(1) and Shibuya H(1) and Matsumoto H(1) and Morisada T(1) and Kobayashi Y(1).},
	title = {Associations of Lipid Metabolism Abnormalities and Obesity With Endometriosis-Associated Ovarian Cancer.},
	journal = {J Obstet Gynaecol Res},
	year = {2026},
	abstract = {AIM: To investigate the differences in lipid metabolism and obesity between patients with ovarian endometrioid carcinoma (OEC) and ovarian clear cell carcinoma (OCCC), both of which are classified as endometriosis-associated Type I ovarian cancers. METHODS: This retrospective study included 133 patients who underwent surgery for OEC (n = 50) or OCCC (n = 83) between 2010 and 2022. Preoperative serum lipid markers (total cholesterol [TC], low-density lipoprotein cholesterol [LDL-C], and high-density lipoprotein cholesterol [HDL-C]) and body mass index (BMI) were compared between the two groups. Associations with menopausal status and disease stage were examined, and independent predictors were evaluated by multivariate logistic regression. RESULTS: Patients with OEC had significantly higher TC (215 vs. 199.5 mg/dL, p = 0.040), LDL-C (139 vs. 120.6 mg/dL, p = 0.026), and BMI (22.1 vs. 20.4 kg/m2, p = 0.020) compared with those with OCCC. No significant differences were observed for HDL-C. In premenopausal women, TC and LDL-C were significantly higher in patients with OEC, whereas no intergroup differences were found in postmenopausal women. Among patients with OEC, those with advanced-stage disease had higher TC and LDL-C, whereas no stage-related differences were observed in patients with OCCC. Multivariate analysis identified BMI and LDL-C as independent factors associated with OEC. CONCLUSION: Lipid metabolism abnormalities and obesity were more strongly associated with OEC than with OCCC, suggesting subtype-specific metabolic mechanisms of carcinogenesis and progression. These findings highlight the importance of metabolic factors in OEC, warranting further prospective studies.},
	doi = {10.1111/jog.70185},
	pmid = {41605467 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/ijms27020917,
	author = {Jäger E(1) and Peeva V(2) and Gnad T(3)(4) and Haange SB(5) and Rolle-Kampczyk U(5), Stäubert C(6) and Krumbholz P(6) and Heiker JT(7) and Gebhardt C(7), Krügel U(8) and Sen P(2) and Harazin M(9) and Stab V(9), Münzker J(1) and Hamdani N(10) and Pfeifer A(3), von Bergen M(5) and Till A(2)(4) and Fenske WK(2)(9).},
	title = {Antibiotic-Mediated Modulation of the Gut Microbiome Identifies Taurine as a Modulator of Adipocyte Function Through TGR5 Signaling.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Gut microbiota has emerged as a modulator of host metabolism and energy balance. However, the precise microbial metabolites mediating thermogenic activation in obesity remain largely undefined. We investigated the effect of antibiotic treatment under a high-fat diet on metabolites and its contribution to lipolysis and thermogenesis. Antibiotic treatment in high-fat diet-fed rats reduced adiposity and enhanced adaptive thermogenesis. Metabolomics revealed elevated taurine levels in the cecum content and plasma of antibiotic-treated animals, correlating with increased expressions of UCP1 and TGR5 in brown adipose tissue. Taurine enhanced lipolysis and oxygen consumption in mouse adipose tissue and human adipocytes. Thereby, taurine modulated lipolysis dependent on TGR5 signaling in adipose tissue. Human data confirmed that taurine promotes browning of white adipocytes and that acute cold exposure leads to a marked drop in circulating taurine, suggesting its rapid recruitment into thermogenic tissues. Besides its synthesis in the liver and dietary uptake, taurine can be a microbiota-derived metabolite that activates adipose thermogenesis and lipolysis through TGR5 and possibly taurine transporter-dependent mechanisms. These findings uncover a gut-adipose axis with therapeutic potential for metabolic disease.},
	doi = {10.3390/ijms27020917},
	pmid = {41596563 [Indexed for MEDLINE]},
	note = {PMC12842370}
}

@ARTICLE{10.3390/ijms27020772,
	author = {Mihaylova LV(1)(2) and Savova MS(1)(2) and Todorova MN(1) and Tonova V(3) and Binev BK(1)(2) and Georgiev MI(1)(2).},
	title = {Cycloastragenol Improves Fatty Acid Metabolism Through NHR-49/FAT-7 Suppression and Potent AAK-2 Activation in Caenorhabditis elegans Obesity Model.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity is among the top contributing factors for non-communicable chronic disease development and has attained menacing global proportions, affecting approximately one of eight adults. Phytochemicals that support energy metabolism and prevent obesity development have been the subject of intense research endeavors over the past several decades. Cycloastragenol is a natural triterpenoid compound and aglycon of astragaloside IV, known for activating telomerase and mitigating cellular aging. Here, we aim to characterize the effect of cycloastragenol on lipid metabolism in a glucose-induced obesity model in Caenorhabditis elegans. We assessed the changes in the body length, width, and area in C. elegans maintained under elevated glucose through automated WormLab system. Lipid accumulation in the presence of either cycloastragenol (100 μM) or orlistat (12 μM), used as a positive anti-obesity control drug, was quantified through Nile Red fluorescent staining. Furthermore, we evaluated the changes in key energy metabolism molecular players in GFP-reporter transgenic strains. Our results revealed that cycloastragenol treatment decreased mean body area and reduced lipid accumulation in the C. elegans glucose-induced model. The mechanistic data indicated that cycloastragenol suppresses the nuclear hormone receptor family member NHR-49 and the delta(9)-fatty-acid desaturase 7 (FAT-7) enzyme, and activates the 5'-AMP-activated protein kinase catalytic subunit alpha-2 (AAK-2) and the protein skinhead 1 (SKN-1) signaling. Collectively, our findings highlight that cycloastragenol reprograms lipid metabolism by down-regulating the insulin-like receptor (daf-2)/phosphatidylinositol 3-kinase (age-1)/NHR-49 signaling while simultaneously enhancing the activity of the AAK-2/NAD-dependent protein deacetylase (SIR-2.1) pathway. The anti-obesogenic potential of cycloastragenol rationalizes further validation in the context of metabolic diseases and obesity management.},
	doi = {10.3390/ijms27020772},
	pmid = {41596421 [Indexed for MEDLINE]},
	note = {PMC12841531}
}
